UPDATE public.reminders SET why = 'When a fire, severe storm, or evacuation hits, families that have rehearsed a plan act in seconds while everyone else loses critical minutes searching for documents and arguing about where to meet. Updating the plan yearly keeps phone numbers, meeting points, and medical info current as kids grow and contacts change.', instructions = ARRAY['Review and update emergency contact list (family, neighbors, doctor, schools, work)','Confirm two meeting locations: one near home, one outside the neighborhood','Update copies of IDs, insurance cards, and medical info in your go-bag','Walk every family member through the evacuation route and shut-off locations (gas, water, electric)','Test communication plan: who calls whom if cell service is down','Replace expired items in emergency kit (water, food, batteries, medications)','Save final plan to phone, fridge, and a cloud document everyone can access']::text[], tools = '[{"name": "Smartphone with notes app", "required": true}, {"name": "Printer", "required": false}]'::jsonb, supplies = '[{"name": "Fireproof document pouch", "estimatedCost": "$20-35", "amazonUrl": "https://www.amazon.com/s?k=fireproof+document+bag"}, {"name": "Emergency contact card pack", "estimatedCost": "$8-12", "amazonUrl": "https://www.amazon.com/s?k=emergency+contact+wallet+card"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=8FH8z9wKoQk', updated_at = now() WHERE id = '4db7c15f-fd3c-4d23-90e6-9afc4a19919f';
UPDATE public.reminders SET why = 'Shared expenses quietly drift out of balance every month — one person picks up groceries, another covers a subscription — and resentment builds when the math is never reconciled. A monthly review keeps the relationship and the budget honest.', updated_at = now() WHERE id = '6154ac2e-c60e-426a-ac73-24a00ec54a9d';
UPDATE public.reminders SET why = 'Annual checkups catch issues like high blood pressure, vision changes, and developmental concerns long before they become expensive emergencies. Skipping them is the single most common reason people end up surprised by a serious diagnosis.', instructions = ARRAY['List every family member and their last checkup date','Call or use patient portals to book annual physicals, dental, and vision','Cluster appointments on the same day or week when possible to limit disruption','Update vaccination records and check school/sports physical requirements','Add appointments to the shared family calendar with reminders 1 week prior','Bring a list of current medications and questions to each visit','File summaries and any test results in your health records folder']::text[], tools = '[{"name": "Shared family calendar", "required": true}, {"name": "Health records app", "required": false}]'::jsonb, supplies = '[{"name": "Family medical binder", "estimatedCost": "$15-25", "amazonUrl": "https://www.amazon.com/s?k=family+medical+records+binder"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=NW3s7NoWnlY', updated_at = now() WHERE id = '08f1ad7c-ff31-4746-b0be-56986547bb72';
UPDATE public.reminders SET why = 'If a fire, theft, or flood happens, insurance only pays for items you can prove you owned. A current photo + receipt inventory is the difference between a full payout and arguing with an adjuster about the TV you swore you had.', instructions = ARRAY['Walk through each room and video-record contents, opening drawers and closets','Photograph serial numbers on electronics and appliances','List high-value items (jewelry, art, tools, instruments) with estimated value and receipts','Save digital copies to cloud storage and an external drive','Compare against last year''s inventory and note additions/disposals','Send the file location and password to a trusted family member']::text[], tools = '[{"name": "Smartphone camera", "required": true}, {"name": "Cloud storage account", "required": true}]'::jsonb, supplies = '[{"name": "External backup drive", "estimatedCost": "$50-90", "amazonUrl": "https://www.amazon.com/s?k=portable+ssd+1tb"}, {"name": "Fireproof safe", "estimatedCost": "$60-150", "amazonUrl": "https://www.amazon.com/s?k=fireproof+document+safe"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=8s8gT6DqkqE', updated_at = now() WHERE id = '8997e5c3-d5d0-4830-aabe-2cd4bf03f2ad';
UPDATE public.reminders SET why = 'Chore imbalance is one of the top sources of household conflict. A scheduled rotation prevents one person from silently absorbing 80% of the work and keeps kids learning all the skills they''ll need on their own.', instructions = ARRAY['List every recurring household chore and how often it''s done','Assign a fair weight (time + effort) to each task','Match chores to age and ability for each family member','Build a rotating weekly schedule on a shared calendar or chore app','Agree on consequences and rewards as a family','Review every 3 months and rebalance based on workload feedback']::text[], tools = '[{"name": "Shared calendar", "required": true}, {"name": "Chore tracking app", "required": false}]'::jsonb, supplies = '[{"name": "Magnetic chore chart", "estimatedCost": "$12-20", "amazonUrl": "https://www.amazon.com/s?k=magnetic+chore+chart+family"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=CdCBsCx9rtE', updated_at = now() WHERE id = 'b77c33fa-a88c-4210-8ed4-ff43577189ce';
UPDATE public.reminders SET why = 'Booking late means paying 30-50% more for the same flights and hotels, plus losing access to the trips that fill up first. Annual planning also forces you to actually take vacation time you''ve earned — most people leave days unused.', instructions = ARRAY['Mark school breaks, holidays, and any blackout work dates on the calendar','Decide on 1 big trip and 2-3 smaller getaways for the year','Set a total travel budget and split it across the trips','Book flights 2-3 months out for domestic, 4-6 months for international','Reserve hotels/rentals with free cancellation when available','Apply for or renew passports at least 6 months before international travel','Buy travel insurance for any trip over $1,500']::text[], tools = '[{"name": "Travel booking app", "required": true}, {"name": "Spreadsheet for budget", "required": false}]'::jsonb, supplies = '[{"name": "Packing cubes", "estimatedCost": "$20-35", "amazonUrl": "https://www.amazon.com/s?k=packing+cubes+set"}, {"name": "Travel document organizer", "estimatedCost": "$15-25", "amazonUrl": "https://www.amazon.com/s?k=passport+travel+wallet+rfid"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=1h4iZSmu6OA', updated_at = now() WHERE id = 'b73109a0-3dcd-4f0f-aef0-d0c04a75ab89';
UPDATE public.reminders SET why = 'Fraud and billing errors are caught in the first 30 days or essentially never — most card issuers cap your liability only if you report within a tight window. A monthly review also surfaces forgotten subscriptions silently draining hundreds of dollars a year.', updated_at = now() WHERE id = '9edcfc4a-a524-43aa-87d1-308225c28375';
UPDATE public.reminders SET why = 'Auto-pay protects your credit score from a single missed payment, which can knock 60-100 points off and cost thousands in higher interest for years. Reviewing it quarterly catches expired cards and double-charges before they cause overdrafts.', instructions = ARRAY['List every recurring bill (utilities, subscriptions, insurance, loans)','Confirm each is on auto-pay from a single primary account','Verify card-on-file is not expiring in the next 90 days','Spot-check last 3 months of charges for amount changes or duplicates','Cancel any subscription you haven''t used in 60 days','Set low-balance alerts on the funding account']::text[], tools = '[{"name": "Online banking app", "required": true}, {"name": "Password manager", "required": false}]'::jsonb, supplies = '[{"name": "Subscription tracker app", "estimatedCost": "$0-5", "amazonUrl": "https://www.amazon.com/s?k=subscription+tracker+app"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=YjbGtK6D6NI', updated_at = now() WHERE id = '6a76668b-e012-47db-916e-264994296132';
UPDATE public.reminders SET why = 'Without a quarterly check, lifestyle creep eats raises and inflation eats savings — both invisibly. Three months is short enough to course-correct and long enough to see real spending patterns.', updated_at = now() WHERE id = 'a2994f9e-cf02-4d6f-8785-da737a475fb9';
UPDATE public.reminders SET why = 'Goals you don''t write down don''t happen — research consistently shows people with explicit, dated financial targets save 2-3x more than people who ''want to save someday.'' Annual review keeps the targets aligned with life changes.', instructions = ARRAY['List your top 3-5 financial goals (emergency fund, debt payoff, retirement, house, college)','Attach a dollar amount and target date to each','Calculate the monthly savings needed for each goal','Compare total monthly need against actual savings capacity','Adjust either the targets or the dates so the math works','Automate transfers on payday for each goal','Schedule a follow-up review in 12 months']::text[], tools = '[{"name": "Spreadsheet or budgeting app", "required": true}, {"name": "Retirement calculator", "required": false}]'::jsonb, supplies = '[{"name": "Personal finance book", "estimatedCost": "$10-20", "amazonUrl": "https://www.amazon.com/s?k=total+money+makeover"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=sVKQn2R7MTk', updated_at = now() WHERE id = '8c3a8889-cc8a-4e10-ad40-9a81491d93d4';
UPDATE public.reminders SET why = 'Insurance companies quietly raise premiums every renewal, and most households are simultaneously over-insured on old cars and under-insured on rebuilt-cost homes. An annual review saves the average family $300-800 and closes coverage gaps before a claim.', instructions = ARRAY['Pull current declarations pages for home, auto, life, and umbrella','Compare deductibles and coverage limits against current home/car values','Get 2-3 competing quotes for each policy','Bundle home + auto with the best carrier for the multi-policy discount','Increase deductibles if you have a healthy emergency fund','Confirm life insurance amount = 10x income or covers all major obligations','File new policy documents in your insurance binder']::text[], tools = '[{"name": "Insurance comparison site", "required": true}, {"name": "Phone for quote calls", "required": false}]'::jsonb, supplies = '[{"name": "Document binder", "estimatedCost": "$10-15", "amazonUrl": "https://www.amazon.com/s?k=insurance+document+binder"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=JotfXM8WUeY', updated_at = now() WHERE id = 'bc011520-4d89-451b-95d7-4b3e291b98a2';
UPDATE public.reminders SET why = 'Beneficiary designations override your will — full stop. An ex-spouse listed on a 401(k) from 15 years ago will inherit it instead of your current family, and the courts cannot fix it. This is the highest-leverage, lowest-effort financial task in existence.', instructions = ARRAY['List every retirement account, life insurance policy, and TOD account','Log into each provider and pull up the current beneficiaries','Confirm primary and contingent beneficiaries are correct and percentages add to 100%','Update any name, marriage, divorce, or death changes','Save confirmation screenshots in your records','Tell your executor where to find the list']::text[], tools = '[{"name": "Provider websites/apps", "required": true}, {"name": "Password manager", "required": true}]'::jsonb, supplies = '[{"name": "Estate planning binder", "estimatedCost": "$15-25", "amazonUrl": "https://www.amazon.com/s?k=estate+planning+binder"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=2N4FKOJh3Gw', updated_at = now() WHERE id = '783e41c0-a103-4139-9ae9-b4fe3c6998ed';
UPDATE public.reminders SET why = 'Late filing penalties are 5% per month plus interest, and missed deductions average $1,200 per household. Getting documents organized early also dramatically reduces audit risk by avoiding rushed estimates.', updated_at = now() WHERE id = '52af17a5-73e4-439c-ade5-7afc155d954a';
UPDATE public.reminders SET why = 'When something happens to you, your family will spend weeks or months hunting for documents in the worst moment of their lives. A single organized folder turns probate from a year-long ordeal into a few weeks.', instructions = ARRAY['Gather: will, power of attorney, healthcare directive, birth certificates, marriage license, deeds, titles, passports','Scan everything to encrypted cloud storage','Keep originals in a fireproof safe or bank safe deposit box','Create a one-page master document listing what is where (account numbers, not passwords)','Share location and access instructions with executor and spouse','Review yearly and after any major life event']::text[], tools = '[{"name": "Scanner or scanner app", "required": true}, {"name": "Fireproof safe", "required": true}]'::jsonb, supplies = '[{"name": "Fireproof document safe", "estimatedCost": "$60-150", "amazonUrl": "https://www.amazon.com/s?k=fireproof+document+safe"}, {"name": "Document folio set", "estimatedCost": "$15-25", "amazonUrl": "https://www.amazon.com/s?k=important+documents+folder"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=5RfprDHUz7E', updated_at = now() WHERE id = '4fbcef92-23a0-4323-be58-77ab67b96434';
UPDATE public.reminders SET why = 'Cavities and gum disease are nearly painless until they''re not — and by then you''re looking at root canals or extractions instead of a $200 cleaning. Annual cleanings prevent 90% of expensive dental work.', updated_at = now() WHERE id = 'ad0d2c22-9f83-41ea-bb8a-808b404ca883';
UPDATE public.reminders SET why = 'Eye exams catch glaucoma, diabetes, and high blood pressure long before symptoms appear — and outdated prescriptions cause headaches, eye strain, and unsafe driving. The exam often pays for itself by spotting issues your physical missed.', updated_at = now() WHERE id = '329652c4-1df0-4bd8-a7a1-51dc59bf6af8';
UPDATE public.reminders SET why = 'Network changes, formulary cuts, and premium hikes happen every year — staying on autopilot can mean your doctor is suddenly out-of-network or your medication isn''t covered. Open enrollment is your one window to fix it.', instructions = ARRAY['Pull last year''s medical, dental, and vision claims','Confirm your doctors and prescriptions are still in-network/covered','Compare HSA/HDHP vs PPO total cost (premiums + expected out-of-pocket)','Review FSA/HSA contribution levels and adjust','Check life and disability coverage through the same enrollment','Submit elections and save confirmation']::text[], tools = '[{"name": "Insurance portal", "required": true}, {"name": "Spreadsheet for cost comparison", "required": false}]'::jsonb, supplies = '[{"name": "Health insurance guide", "estimatedCost": "$10-15", "amazonUrl": "https://www.amazon.com/s?k=health+insurance+for+dummies"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=DTaiFAQumf0', updated_at = now() WHERE id = 'bd8a3a0c-60bf-41ac-9a92-58986a4e3c74';
UPDATE public.reminders SET why = 'Most leading causes of preventable death — heart disease, diabetes, cancer — are easily treatable when caught early through routine bloodwork and screenings. The annual physical is the single highest-ROI hour you''ll spend on your health.', updated_at = now() WHERE id = 'e36283e5-b9a3-4f00-b3f3-3d1eeafa3726';
UPDATE public.reminders SET why = 'Running out of a chronic medication for even a few days can spike blood pressure, blood sugar, or mental health symptoms back to dangerous baselines. A monthly check makes a 5-minute task instead of an emergency.', instructions = ARRAY['Open your pharmacy app and list all active prescriptions','Note pill count remaining and refill dates','Request refills for anything under 14 days','Renew prescriptions with your doctor 30 days before they run out','Set auto-refill for chronic medications','Travel users: request 90-day supplies when possible']::text[], tools = '[{"name": "Pharmacy app", "required": true}, {"name": "Pill organizer", "required": false}]'::jsonb, supplies = '[{"name": "Weekly pill organizer", "estimatedCost": "$8-15", "amazonUrl": "https://www.amazon.com/s?k=weekly+pill+organizer+am+pm"}, {"name": "Medication tracking journal", "estimatedCost": "$10-15", "amazonUrl": "https://www.amazon.com/s?k=medication+log+book"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=g6oI3gJN4Ug', updated_at = now() WHERE id = 'e22bfcf4-7557-46f4-836e-a65039024775';
UPDATE public.reminders SET why = 'Melanoma is one of the few cancers a non-doctor can spot early — and early-stage skin cancer has a 99% survival rate while late-stage drops to 32%. A 10-minute self-check yearly is genuinely lifesaving.', instructions = ARRAY['Stand in good light in front of a full-length mirror','Use the ABCDE rule: Asymmetry, Border, Color, Diameter >6mm, Evolving','Check scalp, behind ears, between fingers and toes, soles of feet','Have a partner check your back and other hard-to-see areas','Photograph any concerning spots with a ruler for size reference','Schedule a dermatologist appointment for anything new, changing, or unusual']::text[], tools = '[{"name": "Full-length mirror", "required": true}, {"name": "Hand mirror", "required": true}, {"name": "Smartphone camera", "required": true}]'::jsonb, supplies = '[{"name": "Mole tracking ruler", "estimatedCost": "$5-10", "amazonUrl": "https://www.amazon.com/s?k=skin+check+mole+ruler"}, {"name": "Mineral sunscreen SPF 50", "estimatedCost": "$12-20", "amazonUrl": "https://www.amazon.com/s?k=mineral+sunscreen+spf+50"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=fNxgwLEQ_8E', updated_at = now() WHERE id = '791293a8-5354-4de7-8b5f-b39d10f764cd';
UPDATE public.reminders SET why = 'Flu and pneumonia kill tens of thousands of healthy adults every year, and tetanus, shingles, and Tdap boosters all expire silently. A 30-minute pharmacy visit prevents weeks of illness or worse.', instructions = ARRAY['Pull up your vaccination history (state portal or doctor''s office)','List shots due: annual flu, COVID booster, Tdap (every 10 yrs), shingles (50+), pneumococcal (65+)','Check pharmacy or workplace clinic availability and pricing','Confirm insurance coverage so you owe $0 at the counter','Get the shot and save the receipt to your health record','Schedule next year''s reminder']::text[], tools = '[{"name": "Insurance card", "required": true}, {"name": "Vaccine record (digital or paper)", "required": true}]'::jsonb, supplies = '[{"name": "Vaccine record card holder", "estimatedCost": "$5-10", "amazonUrl": "https://www.amazon.com/s?k=vaccine+card+holder"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=-muIoWofsCE', updated_at = now() WHERE id = '667ae1da-d3e3-4773-9a89-8c6180cf6ae4';
UPDATE public.reminders SET why = 'Depression, anxiety, and burnout build slowly and feel normal until they''re severe. A scheduled check-in — even when you ''feel fine'' — catches the slide early and normalizes care for everyone in the family.', instructions = ARRAY['Take a free screening (PHQ-9 for depression, GAD-7 for anxiety) online','Honestly review sleep, appetite, energy, mood, and connection over the past month','If you have a therapist, book the next session','If not, ask your PCP for a referral or use your insurance directory','Telehealth platforms (Talkspace, BetterHelp) are an option for fast access','Tell one trusted person how you''re doing']::text[], tools = '[{"name": "Online screening tool", "required": true}, {"name": "Insurance provider directory", "required": true}]'::jsonb, supplies = '[{"name": "Mood/journal book", "estimatedCost": "$10-20", "amazonUrl": "https://www.amazon.com/s?k=mood+journal"}, {"name": "Meditation app subscription", "estimatedCost": "$0-15/mo", "amazonUrl": "https://www.amazon.com/s?k=meditation+app"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=DxIDKZHW3-E', updated_at = now() WHERE id = 'ea9cb905-f834-434a-86b0-05692cc15572';
UPDATE public.reminders SET why = 'Dishwasher leaks are the #2 source of homeowner insurance claims and frequently destroy floors and cabinets before anyone notices. A 15-minute check catches loose hose clamps and worn door gaskets before they soak the kitchen.', estimated_budget = '$0-15', instructions = ARRAY['Pull the dishwasher slightly forward and check the floor underneath for moisture or stains','Inspect the door gasket for cracks, tears, or food debris and clean with mild soap','Run a short cycle and watch the door, hose connections, and cabinet floor for drips','Check the supply line and drain hose connections under the sink for tightness','Clean the filter at the bottom of the tub and check spray arms for blockage','If you spot any leak, mark it with tape and schedule a repair before the next use']::text[], tools = '[{"name": "Flashlight", "required": true}, {"name": "Adjustable wrench", "required": true}, {"name": "Paper towels", "required": true}]'::jsonb, supplies = '[{"name": "Dishwasher gasket", "estimatedCost": "$15-30", "amazonUrl": "https://www.amazon.com/s?k=dishwasher+door+gasket+universal"}, {"name": "Dishwasher cleaner tablets", "estimatedCost": "$8-12", "amazonUrl": "https://www.amazon.com/s?k=affresh+dishwasher+cleaner"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=3LvMnjL4eP4', updated_at = now() WHERE id = '47a91714-8524-43b7-a1e6-a64c2549fa3e';
UPDATE public.reminders SET why = 'Dust-clogged coils make the compressor work 30-50% harder, shaving years off the fridge''s life and adding $50-100/year to the electric bill. It''s the single most impactful 30-minute maintenance task in the kitchen.', estimated_budget = '$10-25', instructions = ARRAY['Unplug the refrigerator at the wall','Pull the fridge away from the wall (a slider mat helps on hardwood)','Remove the kick plate or rear access panel to expose the coils','Vacuum coils with a brush attachment, then use a coil brush for stubborn dust','Wipe up dust on the floor and behind the unit','Empty and rinse the drip tray under the unit','Replace panels, push the fridge back, and plug it in']::text[], tools = '[{"name": "Vacuum with brush attachment", "required": true}, {"name": "Coil cleaning brush", "required": true}, {"name": "Screwdriver", "required": true}]'::jsonb, supplies = '[{"name": "Refrigerator coil brush", "estimatedCost": "$10-15", "amazonUrl": "https://www.amazon.com/s?k=refrigerator+coil+cleaning+brush"}, {"name": "Appliance slider pads", "estimatedCost": "$8-15", "amazonUrl": "https://www.amazon.com/s?k=appliance+furniture+sliders"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=hLVLp8JXVS4', updated_at = now() WHERE id = '4ad8aeb9-a8f9-4f29-8082-056103f417bd';
UPDATE public.reminders SET why = 'Summer ambient heat forces fridges into overdrive — coils, gaskets, and drip pans that are dirty or cracked turn into the biggest energy hog in the house and the most likely source of mid-season breakdowns.', estimated_budget = '$10-25', instructions = ARRAY['Unplug the fridge and pull it away from the wall','Vacuum coils and brush off dust on the compressor','Clean the door gasket with warm soapy water; check for cracks','Empty and clean the drip pan underneath','Verify temperature: fridge 37°F, freezer 0°F','Clear any blocked vents inside the unit','Push back, plug in, and confirm it cycles on cleanly']::text[], tools = '[{"name": "Vacuum", "required": true}, {"name": "Coil brush", "required": true}, {"name": "Refrigerator thermometer", "required": true}]'::jsonb, supplies = '[{"name": "Coil cleaning brush", "estimatedCost": "$10-15", "amazonUrl": "https://www.amazon.com/s?k=refrigerator+coil+brush"}, {"name": "Appliance thermometer", "estimatedCost": "$8-12", "amazonUrl": "https://www.amazon.com/s?k=refrigerator+freezer+thermometer"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=hLVLp8JXVS4', updated_at = now() WHERE id = '1c2a5851-f51f-4766-87a0-39982cdd517d';
UPDATE public.reminders SET why = 'An hour of tuneups before the holidays prevents the worst time of year for an oven, fridge, or dryer to break — when service appointments are 2-3 weeks out and replacement units are back-ordered.', estimated_budget = '$25-60', instructions = ARRAY['Run a cleaning cycle on the oven and check the door seal','Vacuum dryer lint trap housing and inspect the vent hose for blockage','Clean refrigerator coils and replace water filter','Run a dishwasher cleaning cycle and clear the filter','Check washing machine hoses for bulges or cracks','Test microwave for hot spots with a cup of water','Note any unit older than 10 years for proactive replacement planning']::text[], tools = '[{"name": "Vacuum", "required": true}, {"name": "Screwdriver", "required": true}, {"name": "Flashlight", "required": true}]'::jsonb, supplies = '[{"name": "Appliance cleaner pack", "estimatedCost": "$20-30", "amazonUrl": "https://www.amazon.com/s?k=appliance+cleaner+bundle"}, {"name": "Dryer vent brush kit", "estimatedCost": "$15-25", "amazonUrl": "https://www.amazon.com/s?k=dryer+vent+cleaning+kit"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=cz5MS80n7OE', updated_at = now() WHERE id = '8dbbc354-ebcd-4613-974f-ff76e2e4ba49';
UPDATE public.reminders SET why = 'Carpets trap dust mites, allergens, and pet dander that vacuums alone can''t reach — annual deep cleaning measurably reduces allergy symptoms and doubles carpet lifespan, which is the most expensive flooring per square foot to replace.', estimated_budget = '$80-300', instructions = ARRAY['Vacuum thoroughly to remove loose dirt','Pre-treat stains with a carpet stain remover and let sit 5-10 minutes','Rent or use a hot-water extraction machine with carpet shampoo','Work in slow, overlapping passes — wet first, then dry pass','Open windows and run fans to dry within 6-12 hours','Stay off carpets until completely dry','Vacuum once more after drying to lift the pile']::text[], tools = '[{"name": "Carpet cleaning machine", "required": true}, {"name": "Vacuum", "required": true}]'::jsonb, supplies = '[{"name": "Carpet shampoo", "estimatedCost": "$15-30", "amazonUrl": "https://www.amazon.com/s?k=bissell+carpet+shampoo"}, {"name": "Stain pre-treatment spray", "estimatedCost": "$10-15", "amazonUrl": "https://www.amazon.com/s?k=carpet+stain+remover+spray"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=8CzNTwd8RZ0', updated_at = now() WHERE id = 'ee0d94b8-c2e0-4cef-bd55-347f12ed95ac';
UPDATE public.reminders SET why = 'A funky-smelling disposal is colonized bacteria spraying back into the air every time you run the sink. A 10-minute monthly clean prevents both the smell and a clogged drain that can flood the cabinet below.', estimated_budget = '$5-15', instructions = ARRAY['Run cold water and grind a tray of ice cubes to scour the blades','Drop in a cup of baking soda, let sit 10 minutes','Slowly pour in a cup of white vinegar; let it fizz for 5 minutes','Flush with hot water for 30 seconds','Grind citrus peels (lemon or orange) for fresh scent','Wipe the rubber splash guard with soapy water']::text[], tools = '[{"name": "Ice cube tray", "required": true}, {"name": "Sink stopper", "required": false}]'::jsonb, supplies = '[{"name": "Disposal cleaner pods", "estimatedCost": "$8-12", "amazonUrl": "https://www.amazon.com/s?k=garbage+disposal+cleaner+pods"}, {"name": "Baking soda + vinegar", "estimatedCost": "$5-8", "amazonUrl": "https://www.amazon.com/s?k=baking+soda+vinegar+bulk"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=YA8Xv-c4qNo', updated_at = now() WHERE id = '74155352-e7b6-4d3c-8482-9f8ea91c7429';
UPDATE public.reminders SET why = 'Grease-clogged exhaust filters lose suction, fail to vent moisture and smoke, and become a fire hazard. Cleaning the filter quarterly is the cheapest insurance against a kitchen fire and keeps cabinets from yellowing.', estimated_budget = '$5-15', instructions = ARRAY['Turn off the fan and the breaker for safety','Slide out the metal mesh filter(s)','Soak in hot water with grease-cutting dish soap and baking soda for 15 minutes','Scrub with a soft brush, rinse, and air-dry','Wipe the fan housing and blades with a degreaser','Replace any charcoal filter (recirculating hoods only)','Reinstall and run on high to confirm airflow']::text[], tools = '[{"name": "Soft scrub brush", "required": true}, {"name": "Microfiber cloth", "required": true}, {"name": "Sink or large basin", "required": true}]'::jsonb, supplies = '[{"name": "Degreaser spray", "estimatedCost": "$8-12", "amazonUrl": "https://www.amazon.com/s?k=kitchen+degreaser+spray"}, {"name": "Replacement charcoal filter", "estimatedCost": "$10-20", "amazonUrl": "https://www.amazon.com/s?k=range+hood+charcoal+filter"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=YN0HrVgVcKw', updated_at = now() WHERE id = 'afa832ba-710d-472f-bb8c-d90af8dcc8f6';
UPDATE public.reminders SET why = 'Frayed cords cause about 5,300 home fires every year. A monthly walkthrough catches damage from pets, vacuum cleaners, and pinched-under-furniture wear before a wire shorts inside a wall.', estimated_budget = '$10-40', instructions = ARRAY['Walk every room and inspect every visible cord under furniture and behind electronics','Look for cracks, exposed wire, scorch marks, or melted plastic','Feel cords near plugs — warm is fine, hot means trouble','Replace any damaged cord immediately; do not tape repairs','Verify nothing is run under rugs or pinched by furniture legs','Check power strips for overloading and replace any older than 5 years']::text[], tools = '[{"name": "Flashlight", "required": true}, {"name": "Outlet tester", "required": false}]'::jsonb, supplies = '[{"name": "Surge protector power strip", "estimatedCost": "$20-40", "amazonUrl": "https://www.amazon.com/s?k=surge+protector+power+strip"}, {"name": "Cord covers/protectors", "estimatedCost": "$10-20", "amazonUrl": "https://www.amazon.com/s?k=floor+cord+cover"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=eyBJ7n4ofVk', updated_at = now() WHERE id = '4d8ddad6-f143-414c-843a-e481c1dd578a';
UPDATE public.reminders SET why = 'Working smoke alarms cut the risk of dying in a home fire roughly in half. Code requires one on every floor, outside every sleeping area, and inside every bedroom — most homes have less.', estimated_budget = '$60-150', instructions = ARRAY['Plan one detector inside every bedroom, outside each sleeping area, and on every floor including basement','Choose photoelectric or dual-sensor units; interconnected (wired or wireless) is best','Mount on the ceiling at least 4 inches from any wall, or high on a wall 4-12 inches from ceiling','Avoid mounting within 10 feet of cooking appliances','Wire-connect to existing units if possible, or use battery-powered with 10-year batteries','Press test button and verify all interconnected units sound','Label each unit with installation date']::text[], tools = '[{"name": "Drill", "required": true}, {"name": "Step ladder", "required": true}, {"name": "Screwdriver", "required": true}]'::jsonb, supplies = '[{"name": "Smoke + CO detector 3-pack", "estimatedCost": "$60-120", "amazonUrl": "https://www.amazon.com/s?k=first+alert+smoke+co+detector+3+pack"}, {"name": "Drywall anchors", "estimatedCost": "$5-10", "amazonUrl": "https://www.amazon.com/s?k=drywall+anchors"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=F4yFFyLXMWI', updated_at = now() WHERE id = '77006b09-4f52-4f1e-8172-ecb0324c56b9';
UPDATE public.reminders SET why = 'Clogged gutters back up under shingles, rot fascia boards, and route water against the foundation — the leading cause of basement flooding. Cleaning twice a year prevents thousands in water damage.', difficulty = 'Hard', estimated_budget = '$30-100', instructions = ARRAY['Set up a sturdy extension ladder on level ground with a stabilizer','Wear gloves and safety glasses','Scoop debris by hand or with a gutter scoop into a bucket','Flush gutters with a hose to test flow toward downspouts','Snake or flush downspouts that are clogged','Inspect gutter hangers and reseal any leaking seams','Trim back overhanging branches that drop debris']::text[], tools = '[{"name": "Extension ladder", "required": true}, {"name": "Gutter scoop", "required": true}, {"name": "Garden hose", "required": true}, {"name": "Work gloves", "required": true}]'::jsonb, supplies = '[{"name": "Gutter sealant", "estimatedCost": "$8-15", "amazonUrl": "https://www.amazon.com/s?k=gutter+sealant+tube"}, {"name": "Gutter guards", "estimatedCost": "$30-80", "amazonUrl": "https://www.amazon.com/s?k=gutter+guards+leaf+protection"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=qLuyhVJSv7E', updated_at = now() WHERE id = '9bdbc059-44b6-4dc3-8881-526d84eccfbe';
UPDATE public.reminders SET why = 'Clogged screens cut airflow into the home and trap pollen, making allergy season miserable and forcing the AC to work harder. Annual cleaning also doubles screen lifespan.', estimated_budget = '$5-20', instructions = ARRAY['Remove screens from windows and doors','Lay flat on a tarp or driveway','Vacuum both sides with a brush attachment','Scrub with warm soapy water and a soft brush','Rinse with a low-pressure hose','Air-dry fully before reinstalling','Repair any small holes with a screen patch kit']::text[], tools = '[{"name": "Vacuum with brush", "required": true}, {"name": "Soft scrub brush", "required": true}, {"name": "Garden hose", "required": true}]'::jsonb, supplies = '[{"name": "Screen patch kit", "estimatedCost": "$8-12", "amazonUrl": "https://www.amazon.com/s?k=window+screen+patch+kit"}, {"name": "Mild dish soap", "estimatedCost": "$3-5", "amazonUrl": "https://www.amazon.com/s?k=dawn+dish+soap"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=VnYMPXkUR9c', updated_at = now() WHERE id = '5554e6b3-32b3-4792-aa9d-b64f1bbcdd48';
UPDATE public.reminders SET why = 'Properly timed fertilizer crowds out weeds, reduces watering needs, and prevents bare patches that turn into mud and erosion. The wrong timing or product, however, burns the lawn — so doing it right matters.', estimated_budget = '$40-100', instructions = ARRAY['Test soil pH (most lawns want 6.0-7.0); adjust with lime or sulfur if needed','Choose fertilizer based on grass type and season (spring, summer, fall blends differ)','Mow lawn 2-3 days before fertilizing','Apply with a calibrated broadcast or drop spreader for even coverage','Water in lightly within 24 hours unless using a slow-release product','Stay off the lawn for 24-48 hours and keep pets clear','Log application date and product for next season''s reference']::text[], tools = '[{"name": "Broadcast or drop spreader", "required": true}, {"name": "Garden hose", "required": true}]'::jsonb, supplies = '[{"name": "Lawn fertilizer (season-appropriate)", "estimatedCost": "$30-60", "amazonUrl": "https://www.amazon.com/s?k=scotts+turf+builder+lawn+fertilizer"}, {"name": "Soil pH test kit", "estimatedCost": "$10-20", "amazonUrl": "https://www.amazon.com/s?k=soil+ph+test+kit"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=Ezta73kzpe0', updated_at = now() WHERE id = '26a04e7b-afb3-4c0d-aa15-8e12f61d2903';
UPDATE public.reminders SET why = 'Creosote buildup is the #1 cause of chimney fires, and freeze-thaw damage cracks flue liners that let carbon monoxide leak into the home. Annual inspection is non-negotiable for any wood-burning fireplace.', estimated_budget = '$150-400', instructions = ARRAY['Visually inspect crown, cap, and flashing from the ground with binoculars','Check inside the firebox for cracked bricks or mortar','Look up the flue with a flashlight; >1/8" creosote = sweep needed','Hire a CSIA-certified sweep for full inspection and cleaning','Confirm the cap and screen are intact (keeps animals and rain out)','Test fireplace damper opens and closes fully','Save inspection report for insurance']::text[], tools = '[{"name": "Binoculars", "required": true}, {"name": "Flashlight", "required": true}, {"name": "Mirror", "required": false}]'::jsonb, supplies = '[{"name": "Creosote remover log", "estimatedCost": "$15-25", "amazonUrl": "https://www.amazon.com/s?k=csl+creosote+sweeping+log"}, {"name": "Chimney cap", "estimatedCost": "$60-150", "amazonUrl": "https://www.amazon.com/s?k=stainless+steel+chimney+cap"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=NrQ9bYrYlH4', updated_at = now() WHERE id = '850ff39e-9a9b-4245-8da8-395e995e3a60';
UPDATE public.reminders SET why = 'Loose strike plates and worn deadbolts are how most break-ins succeed — a single hard kick. A 30-minute annual check tightens hardware and identifies locks that need upgrading.', estimated_budget = '$10-60', instructions = ARRAY['Tighten hinge screws on every exterior door (replace short screws with 3-inch screws into the framing)','Test each deadbolt for smooth throw — lubricate with graphite if sticky','Tighten strike plate screws and confirm they engage the deadbolt fully','Lubricate squeaky hinges with silicone or white lithium spray','Replace any cracked or corroded hardware','Verify weather stripping seals tight when door is closed']::text[], tools = '[{"name": "Screwdriver", "required": true}, {"name": "Drill", "required": false}, {"name": "Lubricant", "required": true}]'::jsonb, supplies = '[{"name": "3-inch wood screws", "estimatedCost": "$5-10", "amazonUrl": "https://www.amazon.com/s?k=3+inch+wood+screws"}, {"name": "Graphite/lock lubricant", "estimatedCost": "$5-10", "amazonUrl": "https://www.amazon.com/s?k=graphite+lock+lubricant"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=GRsqCLpkGzc', updated_at = now() WHERE id = '52db6c72-0249-4e66-b9df-423488958171';
UPDATE public.reminders SET why = 'A single missing shingle or flashing crack lets water travel feet inside the roof deck before it ever appears on a ceiling — by which point the rot is extensive and uninsured. Annual inspection catches issues at the $50 fix stage.', difficulty = 'Hard', estimated_budget = '$0-300', instructions = ARRAY['Use binoculars from the ground to scan all roof slopes','Look for missing, cracked, curling, or missing shingles','Check flashing around chimneys, vents, and skylights for gaps','Inspect attic underside for water stains, light through the deck, or daylight at vents','Check gutters for shingle granules — heavy granule loss = aging shingles','Hire a roofer for a closer look if anything is unclear; never walk steep or wet roofs']::text[], tools = '[{"name": "Binoculars", "required": true}, {"name": "Flashlight", "required": true}, {"name": "Extension ladder", "required": false}]'::jsonb, supplies = '[{"name": "Roof sealant", "estimatedCost": "$8-15", "amazonUrl": "https://www.amazon.com/s?k=roof+sealant+tube"}, {"name": "Replacement shingles bundle", "estimatedCost": "$30-50", "amazonUrl": "https://www.amazon.com/s?k=asphalt+shingles+bundle"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=bvxV3rHuyMo', updated_at = now() WHERE id = 'b235ae36-d8bc-4f09-8af4-dee4abab9252';
UPDATE public.reminders SET why = 'Mildew and pollen on siding hold moisture against your home''s exterior, accelerating paint failure and rot. An annual wash both extends paint life and dramatically improves curb appeal.', estimated_budget = '$30-150', instructions = ARRAY['Cover plants and outdoor outlets','Close all windows and doors fully','Use a low-pressure tip (white 40°) and detergent designed for house wash','Apply detergent bottom-up, rinse top-down to avoid streaks','Stay 18-24 inches from siding; never aim up under siding laps','Avoid spraying directly at windows and electrical fixtures','Let dry fully before touch-up paint or caulk work']::text[], tools = '[{"name": "Pressure washer", "required": true}, {"name": "House-wash detergent", "required": true}, {"name": "Garden hose", "required": true}]'::jsonb, supplies = '[{"name": "House wash detergent", "estimatedCost": "$15-25", "amazonUrl": "https://www.amazon.com/s?k=krud+kutter+house+wash"}, {"name": "Pressure washer extension wand", "estimatedCost": "$30-60", "amazonUrl": "https://www.amazon.com/s?k=pressure+washer+extension+wand"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=9EXjEWSAdig', updated_at = now() WHERE id = '66a1a144-fd57-4a9f-9bb6-51336086c69f';
UPDATE public.reminders SET why = 'Wet leaves left on grass smother it and breed lawn disease over winter, leaving bald patches that take all spring to recover. Aeration in fall lets roots grow deeper before frost — the single best thing you can do for next year''s lawn.', estimated_budget = '$30-120', instructions = ARRAY['Mow lawn one final time short (~2 inches)','Rake or mulch-mow leaves so no thick layers remain','Rent or buy a core aerator and run two passes in opposite directions','Leave plugs on the lawn — they break down naturally','Overseed bare or thin areas immediately after aerating','Apply a starter fertilizer and water lightly','Bag leaves for composting or municipal pickup']::text[], tools = '[{"name": "Rake or mulching mower", "required": true}, {"name": "Core aerator", "required": true}, {"name": "Spreader", "required": true}]'::jsonb, supplies = '[{"name": "Grass seed", "estimatedCost": "$25-50", "amazonUrl": "https://www.amazon.com/s?k=grass+seed+perennial+mix"}, {"name": "Starter fertilizer", "estimatedCost": "$20-35", "amazonUrl": "https://www.amazon.com/s?k=starter+fertilizer+overseed"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=O4vBUEY8R3M', updated_at = now() WHERE id = 'c8d3c319-781f-4509-a9ef-e8840fcdcb98';
UPDATE public.reminders SET why = 'An unsealed deck loses 1/8" of wood per year to UV and rain — and once boards cup or split, they have to be replaced at 5-10x the cost of refinishing. Annual stain renewal is the single biggest deck life-extender.', frequency = 'yearly', estimated_budget = '$80-300', instructions = ARRAY['Sweep deck and clear all furniture and planters','Wash with deck cleaner; rinse with low-pressure hose','Allow 48 hours to fully dry','Sand any splintered or rough boards','Replace popped fasteners with deck screws','Apply stain or sealer with a roller and brush, working with the grain','Apply 1-2 coats per product directions; let cure 24-48 hours']::text[], tools = '[{"name": "Pressure washer or hose", "required": true}, {"name": "Sander", "required": true}, {"name": "Stain pad/roller", "required": true}, {"name": "Brush", "required": true}]'::jsonb, supplies = '[{"name": "Deck stain/sealer (5 gal)", "estimatedCost": "$40-90", "amazonUrl": "https://www.amazon.com/s?k=thompsons+waterseal+deck"}, {"name": "Deck cleaner", "estimatedCost": "$15-25", "amazonUrl": "https://www.amazon.com/s?k=deck+cleaner+brightener"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=DvhJ-RsVnww', updated_at = now() WHERE id = '0bdc25c9-d21a-4208-b4e4-a81dbd2e919e';
UPDATE public.reminders SET why = 'Drafty single-pane windows can account for 25-30% of a home''s heating and cooling loss. Replacing them with energy-efficient units cuts utility bills, reduces outside noise, and qualifies for federal tax credits.', frequency = 'yearly', estimated_budget = '$300-1200', instructions = ARRAY['Inspect each window for drafts using a candle or smoke pen','Identify the worst offenders for priority replacement','Get 3 quotes from licensed window installers','Choose ENERGY STAR-rated windows appropriate for your climate zone','Schedule installation during mild weather','Confirm warranty terms (frame, glass, labor) in writing','File for any energy efficiency tax credits or utility rebates']::text[], tools = '[{"name": "Smoke pen or candle", "required": true}, {"name": "Tape measure", "required": true}]'::jsonb, supplies = '[{"name": "Temporary window film", "estimatedCost": "$15-30", "amazonUrl": "https://www.amazon.com/s?k=window+insulation+kit+shrink"}, {"name": "Weather stripping", "estimatedCost": "$10-20", "amazonUrl": "https://www.amazon.com/s?k=window+weather+stripping"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=k-Hrd9bb6Mw', updated_at = now() WHERE id = '598df1f7-6a5b-4416-8c11-81639f5f0ffe';
UPDATE public.reminders SET why = 'Air leaks around windows and doors account for 10-20% of total heating and cooling costs. An afternoon with caulk and weather stripping pays for itself within one season.', estimated_budget = '$25-80', instructions = ARRAY['Find drafts using a candle or smoke pen along window/door edges','Scrape out failed caulk with a putty knife','Clean surfaces with a damp cloth and let dry','Apply silicone or polyurethane caulk in a continuous bead','Smooth with a wet finger or tool','Replace torn or compressed weather stripping along door jambs','Add door sweeps to exterior doors with daylight at the bottom']::text[], tools = '[{"name": "Caulk gun", "required": true}, {"name": "Putty knife", "required": true}, {"name": "Smoke pen", "required": true}]'::jsonb, supplies = '[{"name": "Exterior silicone caulk", "estimatedCost": "$8-12", "amazonUrl": "https://www.amazon.com/s?k=ge+silicone+caulk+exterior"}, {"name": "Weather stripping kit", "estimatedCost": "$15-25", "amazonUrl": "https://www.amazon.com/s?k=weather+stripping+kit+door+window"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=xMqIWSe1L2I', updated_at = now() WHERE id = '1d2a2c35-a95b-475b-a479-d3e4595a0a1c';
UPDATE public.reminders SET why = 'Spring storms drop a fresh layer of pollen, seeds, and twigs that re-clog gutters within weeks of the last cleaning. A spring pass keeps water flowing during the year''s heaviest rain months.', difficulty = 'Hard', estimated_budget = '$30-100', instructions = ARRAY['Set up a stable ladder with a stabilizer/standoff','Scoop debris into a bucket','Flush with a hose to confirm flow toward downspouts','Clear any clogged downspouts with a plumbing snake','Reseal leaking seams with gutter sealant','Reattach any sagging gutter sections']::text[], tools = '[{"name": "Extension ladder", "required": true}, {"name": "Gutter scoop", "required": true}, {"name": "Hose", "required": true}, {"name": "Bucket", "required": true}]'::jsonb, supplies = '[{"name": "Gutter sealant", "estimatedCost": "$8-15", "amazonUrl": "https://www.amazon.com/s?k=gutter+sealant"}, {"name": "Replacement hangers", "estimatedCost": "$10-20", "amazonUrl": "https://www.amazon.com/s?k=gutter+hidden+hangers"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=qLuyhVJSv7E', updated_at = now() WHERE id = 'a28ac186-725e-403b-b636-91e54fb8039a';
UPDATE public.reminders SET why = 'Winter leaves siding caked with salt, dirt, and mildew that locks moisture against the wall. A spring wash refreshes curb appeal and prevents premature paint failure.', estimated_budget = '$30-150', instructions = ARRAY['Cover landscaping and shut windows','Apply house wash detergent bottom-up with a low-pressure tip','Let dwell 5-10 minutes (do not let dry)','Rinse top-down with low pressure','Avoid spraying upward under siding laps','Spot-treat any remaining mildew with diluted bleach solution']::text[], tools = '[{"name": "Pressure washer", "required": true}, {"name": "House-wash detergent", "required": true}]'::jsonb, supplies = '[{"name": "House wash concentrate", "estimatedCost": "$15-25", "amazonUrl": "https://www.amazon.com/s?k=krud+kutter+house+wash"}, {"name": "Outdoor mildew remover", "estimatedCost": "$10-20", "amazonUrl": "https://www.amazon.com/s?k=wet+and+forget+mildew+remover"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=9EXjEWSAdig', updated_at = now() WHERE id = 'b2920701-3110-4f2b-853b-f6f47ebb5a4d';
UPDATE public.reminders SET why = 'Winter ice and wind loosen flashing, lift shingles, and crack caulk. Catching damage in spring lets repairs happen in dry weather — far cheaper than chasing leaks during the next storm.', difficulty = 'Hard', estimated_budget = '$0-300', instructions = ARRAY['Use binoculars to scan all slopes from the ground','Look for lifted, cracked, or missing shingles','Inspect flashing around chimneys, vents, skylights','Check attic for daylight or water staining','Look at gutters for shingle granules (heavy loss = aging roof)','Hire a roofer for any unclear or unreachable issue']::text[], tools = '[{"name": "Binoculars", "required": true}, {"name": "Flashlight", "required": true}]'::jsonb, supplies = '[{"name": "Roof sealant", "estimatedCost": "$8-15", "amazonUrl": "https://www.amazon.com/s?k=roof+sealant+tube"}, {"name": "Tarps for emergency cover", "estimatedCost": "$15-30", "amazonUrl": "https://www.amazon.com/s?k=heavy+duty+roof+tarp"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=bvxV3rHuyMo', updated_at = now() WHERE id = '88d57aae-d9aa-4074-b409-2755fdff557b';
UPDATE public.reminders SET why = 'Catching paint failure at the chip stage costs an afternoon and $30 — letting it spread to bare wood costs thousands and a full repaint. Annual touch-ups dramatically extend a paint job''s life.', estimated_budget = '$30-100', instructions = ARRAY['Walk the exterior and mark any chipped, peeling, or faded spots','Scrape loose paint and sand smooth','Spot-prime bare wood with exterior primer','Caulk any open seams or nail holes','Apply matching exterior paint with a brush, feathering edges','Allow proper dry time and apply a second coat as needed']::text[], tools = '[{"name": "Scraper", "required": true}, {"name": "Sandpaper", "required": true}, {"name": "Brush", "required": true}, {"name": "Caulk gun", "required": true}]'::jsonb, supplies = '[{"name": "Exterior touch-up paint", "estimatedCost": "$25-50", "amazonUrl": "https://www.amazon.com/s?k=exterior+latex+paint+quart"}, {"name": "Exterior primer", "estimatedCost": "$15-25", "amazonUrl": "https://www.amazon.com/s?k=kilz+exterior+primer"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=Z8WkaW3I_lI', updated_at = now() WHERE id = '6e9d92d2-7742-40bd-9916-ff4e93d42dc1';
UPDATE public.reminders SET why = 'Dirty windows cut natural light by up to 20% — a measurable hit to mood, productivity, and seasonal heating. Inside-and-out washing also removes hard-water spots that etch glass permanently if left.', estimated_budget = '$15-50', instructions = ARRAY['Dust frames and remove cobwebs first','Mix warm water + dish soap (or use a streak-free window cleaner)','Wash with a microfiber cloth or sponge','Squeegee from top to bottom in overlapping S-strokes','Wipe the squeegee blade after each pass','Dry edges with a clean microfiber','Use a step ladder for high windows; never reach from a sill']::text[], tools = '[{"name": "Squeegee", "required": true}, {"name": "Bucket", "required": true}, {"name": "Step ladder", "required": true}, {"name": "Microfiber cloths", "required": true}]'::jsonb, supplies = '[{"name": "Window cleaning kit", "estimatedCost": "$25-40", "amazonUrl": "https://www.amazon.com/s?k=professional+window+cleaning+kit"}, {"name": "Streak-free cleaner", "estimatedCost": "$8-12", "amazonUrl": "https://www.amazon.com/s?k=invisible+glass+cleaner"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=ZAdxlcr2oqo', updated_at = now() WHERE id = 'c482dbbd-890f-4d15-be64-3240cd8f0dc6';
UPDATE public.reminders SET why = 'Insurance claims for storm damage often must be filed within days of the event — and damage that goes unnoticed becomes a denied claim later. A quick post-storm walkaround protects coverage and catches small issues before they spread.', estimated_budget = '$0-50', instructions = ARRAY['Walk the perimeter and look at the roof with binoculars','Check for missing/lifted shingles, displaced flashing, dented vents','Inspect siding for cracks, dents, or holes','Look at fences, decks, and outbuildings for damage','Photograph everything — even questionable items — for insurance records','Report damage to your carrier promptly if it exceeds your deductible']::text[], tools = '[{"name": "Binoculars", "required": true}, {"name": "Smartphone camera", "required": true}, {"name": "Flashlight", "required": true}]'::jsonb, supplies = '[{"name": "Heavy duty tarp", "estimatedCost": "$20-40", "amazonUrl": "https://www.amazon.com/s?k=blue+heavy+duty+tarp"}, {"name": "Roof sealant for emergencies", "estimatedCost": "$10-15", "amazonUrl": "https://www.amazon.com/s?k=roof+sealant+emergency"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=bvxV3rHuyMo', updated_at = now() WHERE id = 'e401ac4e-24c4-400b-8810-91cab0cb3096';
UPDATE public.reminders SET why = 'Unpruned branches over the house become projectiles in the next storm, and dense canopies harbor pests. Annual pruning improves tree health, prevents structural damage, and reduces leaf load in gutters.', estimated_budget = '$30-300', instructions = ARRAY['Identify dead, diseased, crossing, or hanging branches','Prune in late winter for most species (after coldest weather, before bud break)','Cut just outside the branch collar — never flush to trunk','Use loppers for branches up to 1.5", a pruning saw for larger','Never remove more than 25% of a tree in one year','Hire a certified arborist for anything taller than a step ladder reach','Clean up debris and chip or compost where possible']::text[], tools = '[{"name": "Bypass loppers", "required": true}, {"name": "Pruning saw", "required": true}, {"name": "Hand pruners", "required": true}, {"name": "Gloves", "required": true}]'::jsonb, supplies = '[{"name": "Replacement pruner blades", "estimatedCost": "$10-20", "amazonUrl": "https://www.amazon.com/s?k=felco+replacement+blade"}, {"name": "Wound sealant", "estimatedCost": "$8-12", "amazonUrl": "https://www.amazon.com/s?k=tree+wound+sealer"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=8Y-3K3hFpvE', updated_at = now() WHERE id = 'ce48e373-a22e-448c-9ff5-4d6919b82c04';
UPDATE public.reminders SET why = 'Clean screens entering allergy season cut indoor pollen substantially and let you actually open windows again. Skipping it means dirtier indoor air and sneezing for months.', estimated_budget = '$5-20', instructions = ARRAY['Pop screens out of windows and doors','Vacuum both sides with a brush attachment','Lay flat and scrub with warm soapy water','Rinse with low-pressure hose','Air-dry fully','Patch any small holes before reinstalling']::text[], tools = '[{"name": "Vacuum brush", "required": true}, {"name": "Soft brush", "required": true}, {"name": "Hose", "required": true}]'::jsonb, supplies = '[{"name": "Screen patch kit", "estimatedCost": "$8-12", "amazonUrl": "https://www.amazon.com/s?k=window+screen+patch+kit"}, {"name": "Mild detergent", "estimatedCost": "$3-5", "amazonUrl": "https://www.amazon.com/s?k=dish+soap"}]'::jsonb, video_url = 'https://www.youtube.com/watch?v=VnYMPXkUR9c', updated_at = now() WHERE id = '88569976-45ec-4e14-96fe-118615e3545f';

COMMIT;